# --- plot helper (hidden) — Moon descents at different thrusts ---
# Each descent is stepped with the student's OWN lander_step. Falls back per
# curve to the built-in step until lander_step works, so it's never blank.
def __descend_ref(thrust, dt, steps, every):
    g = 1.62; h = 50.0; v = 0.0; t = 0.0
    pts = [[0.0, 50.0]]
    for i in range(steps):
        v += (thrust - g) * dt
        h += v * dt; t += dt
        if h <= 0:
            pts.append([round(t, 2), 0.0]); break
        if i % every == 0:
            pts.append([round(t, 2), round(h, 2)])
    return pts

def __descend_student(thrust, dt, steps, every):
    h = 50.0; v = 0.0; t = 0.0
    pts = [[0.0, 50.0]]
    for i in range(steps):
        res = lander_step(h, v, thrust, 1.62, dt)   # <- the STUDENT's function
        h = res[0]; v = res[1]
        t += dt
        if h <= 0:
            pts.append([round(t, 2), 0.0]); break
        if i % every == 0:
            pts.append([round(t, 2), round(h, 2)])
    return pts

def __plot(_):
    series = []
    for thrust, hot, label in (
        (0.0, False, "engine off (0.0) — crash"),
        (1.0, False, "weak (1.0)"),
        (1.61, True, "strong (1.61) — gentle glide"),
    ):
        try:
            p = __descend_student(thrust, 0.05, 3000, 20)
            if p and len(p) > 1:
                series.append({"name": label, "points": p, "highlight": hot})
                continue
        except Exception:
            pass
        series.append({"name": label, "points": __descend_ref(thrust, 0.05, 3000, 20), "highlight": hot})
    return series
